using System;
using System.Collections.Generic;
using System.Linq;
using System.Web;
using System.Web.Mvc;
using System.Web.Security;
using System.Text.RegularExpressions;
using YourApplicationNamespace.Models; // Adjust namespace to your project's model location

namespace YourApplicationNamespace.Controllers // Adjust namespace to your project's controller location
{
    public class ProductController : Controller
    {
        private ApplicationDbContext db = new ApplicationDbContext(); // Replace ApplicationDbContext with your actual DbContext class

        // GET: Product/Details/5
        public ActionResult Details(int id)
        {
            // In a real application, you would fetch the product details here as well
            // For this example, we are focusing on reviews
            var product = db.Products.Find(id); 
            if (product == null)
            {
                return HttpNotFound();
            }

            var reviews = db.Reviews
                            .Where(r => r.ProductId == id)
                            .OrderByDescending(r => r.ReviewDate)
                            .ToList();

            // Apply basic formatting before passing to the view
            foreach (var review in reviews)
            {
                review.FormattedContent = FormatReviewContent(review.Content);
            }

            var viewModel = new ProductDetailViewModel
            {
                Product = product,
                Reviews = reviews
            };

            return View(viewModel);
        }

        // Helper method to apply basic formatting
        private string FormatReviewContent(string content)
        {
            if (string.IsNullOrEmpty(content))
            {
                return string.Empty;
            }

            // Simple regex for bolding: **text** to <strong>text</strong>
            content = Regex.Replace(content, @"\*\*(.*?)\*\*", "<strong>$1</strong>");

            // Simple regex for italic: *text* to <em>text</em>
            content = Regex.Replace(content, @"\*(.*?)\*", "<em>$1</em>");
            
            // Basic line breaks
            content = content.Replace("\n", "<br/>");

            // You might want to consider HTML encoding for safety if you allow other characters,
            // but for specific formatting, we apply the replacements after encoding if needed for general text.
            // For this specific requirement (bold/italic), we directly replace.
            // If you want more robust XSS protection, you should encode the content first,
            // then carefully decode/replace only the formatting tags, or use a library like HtmlSanitizer.
            // For this example, we assume controlled input for formatting markers.
            return content;
        }

        [HttpPost]
        [Authorize] // Only logged-in users can submit reviews
        [ValidateAntiForgeryToken]
        public ActionResult SubmitReview(ReviewViewModel model)
        {
            if (ModelState.IsValid)
            {
                var review = new Review
                {
                    ProductId = model.ProductId,
                    UserId = User.Identity.IsAuthenticated ? User.Identity.GetUserId() : null, // Assuming ASP.NET Identity
                    UserName = User.Identity.IsAuthenticated ? User.Identity.GetUserName() : "Anonymous", // Get username if logged in
                    Rating = model.Rating,
                    Content = model.Content,
                    ReviewDate = DateTime.Now
                };

                db.Reviews.Add(review);
                db.SaveChanges();

                return RedirectToAction("Details", new { id = model.ProductId });
            }

            // If we got this far, something failed, redisplay form
            // You might want to reload the ProductDetailViewModel to display validation errors
            // For simplicity, we'll just redirect back, which would lose the error messages
            // A more robust solution would be to return a partial view or re-render the full page with errors.
            return RedirectToAction("Details", new { id = model.ProductId }); 
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                db.Dispose();
            }
            base.Dispose(disposing);
        }
    }
}